import React, { Component } from 'react';
import Navitem from './Navitem';
import { saveAs } from 'file-saver';

class Navbar extends Component {
    constructor(props)
    {
        super(props);
        this.state={
            'NavItemActive':''
        }
    }
    activeitem=(x)=>
    {
        if(this.state.NavItemActive.length>0){
            document.getElementById(this.state.NavItemActive).classList.remove('active');
        }
        this.setState({'NavItemActive':x},()=>{
            document.getElementById(this.state.NavItemActive).classList.add('active');
        });
    };
    render() {
        return (
            <nav>
            <ul>
            <Navitem item="About" tolink="/"  activec={this.activeitem}></Navitem>
            <Navitem item="Education" tolink="/education"  activec={this.activeitem}></Navitem>
            <Navitem item="Skills" tolink="/skills"  activec={this.activeitem}></Navitem>
            <Navitem item="Research" tolink="/research"  activec={this.activeitem}></Navitem>
            <Navitem item="Teaching" tolink="/teaching"  activec={this.activeitem}></Navitem>
            <Navitem item="Publication" tolink="/publication"  activec={this.activeitem}></Navitem>
            <Navitem item="Honors" tolink="/honors"  activec={this.activeitem}></Navitem>
            <Navitem item="Contact" tolink="/contact"  activec={this.activeitem}></Navitem>
            <a href="/Resume_Haozhe_CS_21F.pdf"> Resume</a>
            </ul>
            </nav>
            )
        }
    }

    export default Navbar
